import React from "react";
import axios from "axios";

const API = "http://localhost:5064/api/centre-interet"; // Endpoint spécifique aux centres d'intérêt

interface DeleteCentreInteretButtonProps {
    id: number;                  // L'identifiant du centre d'intérêt à supprimer
    onDeleteSuccess: () => void; // Fonction à appeler après une suppression réussie
}

export default function DeleteCentreInteretButton({ id, onDeleteSuccess }: DeleteCentreInteretButtonProps) {
    const handleClick = async () => {
        if (window.confirm("Voulez-vous vraiment supprimer ce centre d'intérêt ?")) {
            try {
                const deleteUrl = `${API}/${id}`;
                console.log("Suppression de l'URL :", deleteUrl);  // Debug : Affiche l'URL de suppression
                await axios.delete(deleteUrl);
                onDeleteSuccess();  // Rafraîchit la liste après suppression
            } catch (error) {
                console.log("Erreur lors de la suppression :", error);
            }
        }
    };

    return (
        <button className="DeleteButton" onClick={handleClick}>
            Supprimer
        </button>
    );
}
